import React, { useCallback, useMemo, useState } from 'react';
import {
  Input,
  Select,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { masterService } from '../../../services/master/masterService';
import { exportCustomerGroupsCsv } from '../../../services/master/catalogExport';
import type { CustomerGroupDto } from '../../../services/master/models';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useCatalogPagination,
  useServerPagedListLoading,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogLegacyCodeSuffix,
  CatalogListExportButton,
  CatalogCodeReplaceProvider,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
  CatalogRowActionMenu,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
  type ErpListSortState,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import {
  flattenCustomerGroupTree,
  includeCustomerGroupTreeAncestors,
  CUSTOMER_TYPE_LABELS,
  buildCustomerTypeOptionsFromGroups,
  filterCustomerTypeSelectOptions,
  customerGroupRowDepth,
  customerGroupRowCellStyle,
  CUSTOMER_GROUP_INDENT_PX,
  CUSTOMER_GROUP_TREE_PRELOAD_SIZE,
  resolveLevel1FormatCode,
  normalizeCustomerGroupDto,
} from '../../../utils/customerGroupTree';
import {
  filterCatalogListRows,
  applyCatalogColumnFilters,
  applyCatalogColumnSort,
  catalogCellDisplayTextForKey,
} from '../../../utils/catalogListClientSearch';
import { CustomerGroupParentLookupField } from '../../../components/dm/customerGroup/CustomerGroupParentLookupField';
import styles from '../../../styles/erpPage.module.css';
import { normalizeCode } from '../../../utils/codeField';

const TEST_ID = 'dm-nhom-doi-tuong';
const CATALOG_KIND = 'customer-groups';

const LEVEL_FILTER_OPTIONS = [
  { value: '', label: 'Tất cả cấp' },
  { value: '1', label: 'Cấp 1' },
  { value: '2', label: 'Cấp 2' },
  { value: '3', label: 'Cấp 3' },
  { value: '4', label: 'Cấp 4' },
];

const ACTIVE_FILTER_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Ngưng' },
];

type GroupFormState = Partial<CustomerGroupDto> & {
  parentCode?: string;
  parentName?: string;
};

type FormErrors = Partial<Record<'code' | 'formatCode' | 'name' | 'customerType' | 'parentCustomerGroupId', string>>;

const NhomDoiTuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [levelFilter, setLevelFilter] = useState('');
  const [activeFilter, setActiveFilter] = useState('');
  const [items, setItems] = useState<CustomerGroupDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [serverTotalCount, setServerTotalCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CustomerGroupDto | null>(null);
  const [form, setForm] = useState<GroupFormState>({ isActive: true, customerType: 'Customer' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const [columnFilters, setColumnFilters] = useState<Record<string, string[]>>({});
  const [sortState, setSortState] = useState<ErpListSortState>(null);
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const isTreeMode = search.trim().length === 0 && !levelFilter && activeFilter === '';

  const locallyFilteredItems = useMemo(
    () =>
      filterCatalogListRows(
        items as unknown as Record<string, unknown>[],
        searchDraft,
        listColumns,
        row => {
          const g = row as unknown as CustomerGroupDto;
          const typeLabel = g.customerType ? CUSTOMER_TYPE_LABELS[g.customerType] ?? g.customerType : '';
          return typeLabel ? [typeLabel] : [];
        },
      ) as unknown as CustomerGroupDto[],
    [items, searchDraft, listColumns],
  );

  const columnFilteredItems = useMemo(
    () =>
      applyCatalogColumnFilters(
        locallyFilteredItems as unknown as Record<string, unknown>[],
        listColumns,
        columnFilters,
      ) as unknown as CustomerGroupDto[],
    [locallyFilteredItems, listColumns, columnFilters],
  );

  const sortedItems = useMemo(
    () =>
      applyCatalogColumnSort(
        columnFilteredItems as unknown as Record<string, unknown>[],
        listColumns,
        sortState,
      ) as unknown as CustomerGroupDto[],
    [columnFilteredItems, listColumns, sortState],
  );

  const treeFlattenInput = useMemo(
    () => (isTreeMode ? includeCustomerGroupTreeAncestors(sortedItems, items) : sortedItems),
    [isTreeMode, sortedItems, items],
  );

  const displayRows = useMemo(
    () => (isTreeMode ? flattenCustomerGroupTree(treeFlattenInput) : sortedItems),
    [treeFlattenInput, isTreeMode, sortedItems],
  );

  const initFormName = modalOpen && editing ? 'edit-customer-group' : 'create-customer-group';
  const { customerTypeOptions: initTypeOptions } = useVoucherInitData(initFormName);
  const customerTypeOpts = useMemo(
    () => filterCustomerTypeSelectOptions(
      buildCustomerTypeOptionsFromGroups(items, initTypeOptions),
    ),
    [items, initTypeOptions],
  );

  const {
    page: serverPage,
    setPage: setServerPage,
    pageSize: serverPageSize,
    setPageSize: setServerPageSize,
    resetPage: resetServerPage,
  } = useCatalogListPaging();

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService
        .getCustomerGroups({
          search: search || undefined,
          level: levelFilter ? Number(levelFilter) : undefined,
          isActive: activeFilter === '' ? undefined : activeFilter === 'true',
          page: isTreeMode ? 1 : serverPage,
          pageSize: isTreeMode ? CUSTOMER_GROUP_TREE_PRELOAD_SIZE : serverPageSize,
        })
        .then(data => {
          if (!cancelled) {
            setItems(data.items.map(normalizeCustomerGroupDto));
            setServerTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải nhóm đối tượng', type: 'error' });
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, levelFilter, activeFilter, isTreeMode, serverPage, serverPageSize, reloadKey, dispatch]);

  const clientPaging = useCatalogPagination(displayRows);

  const page = isTreeMode ? clientPaging.page : serverPage;
  const setPage = isTreeMode ? clientPaging.setPage : setServerPage;
  const pageSize = isTreeMode ? clientPaging.pageSize : serverPageSize;
  const setPageSize = isTreeMode ? clientPaging.setPageSize : setServerPageSize;
  const totalCount = isTreeMode ? clientPaging.totalCount : serverTotalCount;
  const tableRows = isTreeMode ? clientPaging.pageItems : sortedItems;
  const batchSource = isTreeMode ? displayRows : sortedItems;
  const filterSourceRows = locallyFilteredItems;

  type GroupGridRow = CustomerGroupDto & { id: string };

  const gridRows = useMemo<GroupGridRow[]>(
    () => tableRows.map(r => ({ ...r, id: r.customerGroupId })),
    [tableRows],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.customerGroupId,
    isRowSelectable: () => true,
  });

  const resetPage = useCallback(() => {
    resetServerPage();
    clientPaging.resetPage();
  }, [clientPaging, resetServerPage]);

  const getColumnDisplayValue = useCallback(
    (row: GroupGridRow, columnKey: string) => {
      if (columnKey === 'customerType') {
        const type = row.customerType;
        return type ? CUSTOMER_TYPE_LABELS[type] ?? type : '';
      }
      return catalogCellDisplayTextForKey(
        row as unknown as Record<string, unknown>,
        listColumns,
        columnKey,
      );
    },
    [listColumns],
  );

  const handleColumnFilterConfirm = useCallback(
    (columnKey: string, selectedValues: string[]) => {
      setColumnFilters(prev => ({ ...prev, [columnKey]: selectedValues }));
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleColumnFilterClear = useCallback(
    (columnKey: string) => {
      setColumnFilters(prev => {
        const next = { ...prev };
        delete next[columnKey];
        return next;
      });
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleSortChange = useCallback(
    (sort: ErpListSortState) => {
      setSortState(sort);
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const commitSearch = useCallback(
    (nextSearch?: string) => {
      const q = (nextSearch ?? searchDraft).trim();
      pulseSearch(() => {
        setLoadingMode('filter');
        setSearch(q);
        resetPage();
        selection.clearSelection();
      });
    },
    [pulseSearch, resetPage, searchDraft, selection, setLoadingMode],
  );

  const handleSearch = useCallback(() => {
    commitSearch();
  }, [commitSearch]);

  const handleSearchDraftChange = useCallback(
    (value: string) => {
      setSearchDraft(value);
      if (value.trim().length === 0 && search.trim().length > 0) {
        commitSearch('');
        return;
      }
      if (search.trim().length === 0 && !levelFilter && activeFilter === '') {
        clientPaging.resetPage();
      }
      selection.clearSelection();
    },
    [clientPaging, commitSearch, search, levelFilter, activeFilter, selection],
  );

  const formLevel = useMemo(() => {
    if (editing) return editing.level ?? 1;
    if (form.parentCustomerGroupId) {
      const parent = items.find(g => g.customerGroupId === form.parentCustomerGroupId);
      return (parent?.level ?? 0) + 1;
    }
    return 1;
  }, [editing, form.parentCustomerGroupId, items]);

  const parentLocked = !!editing || viewOnlyShared;
  const customerTypeLocked = parentLocked || !!form.parentCustomerGroupId;
  const inheritedFormatCode = useMemo(() => {
    if (formLevel === 1) return undefined;
    const groupId = editing?.customerGroupId ?? form.parentCustomerGroupId;
    return resolveLevel1FormatCode(groupId, items);
  }, [formLevel, editing, form.parentCustomerGroupId, items]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã nhóm';
    if (formLevel === 1 && !form.formatCode?.trim()) next.formatCode = 'Nhập mã format';
    if (!form.name?.trim()) next.name = 'Nhập tên nhóm';
    if (formLevel === 1 && !form.customerType?.trim()) next.customerType = 'Chọn loại nhóm';
    if (formLevel > 1 && !form.parentCustomerGroupId) next.parentCustomerGroupId = 'Chọn nhóm cha';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const resolveParentDisplay = useCallback((row: CustomerGroupDto) => {
    const parent = row.parentCustomerGroupId
      ? items.find(g => g.customerGroupId === row.parentCustomerGroupId)
      : undefined;
    return {
      parentCode: parent?.code,
      parentName: row.parentName ?? parent?.name,
    };
  }, [items]);

  const openAdd = (parentRow?: CustomerGroupDto) => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({
      isActive: true,
      customerType: parentRow?.customerType ?? 'Customer',
      parentCustomerGroupId: parentRow?.customerGroupId,
      parentCode: parentRow?.code,
      parentName: parentRow?.name,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: CustomerGroupDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    const { parentCode, parentName } = resolveParentDisplay(row);
    setForm({
      ...row,
      parentCustomerGroupId: row.parentCustomerGroupId ?? undefined,
      parentCode,
      parentName,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean, resolveParentDisplay]);

  const openEditImpl = useCallback((row: CustomerGroupDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    const { parentCode, parentName } = resolveParentDisplay(row);
    setForm({
      ...row,
      parentCustomerGroupId: row.parentCustomerGroupId ?? undefined,
      parentCode,
      parentName,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean, resolveParentDisplay]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      const payload = { ...form, level: formLevel };
      if (editing) await masterService.updateCustomerGroup(editing.customerGroupId, payload);
      else await masterService.createCustomerGroup(payload);
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật nhóm đối tượng thành công' : 'Tạo nhóm đối tượng thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? batchSource.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.customerGroupId)
        : [...selection.selectedIds].filter(id => {
            const row = batchSource.find(r => r.customerGroupId === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = batchSource.find(r => r.customerGroupId === id)!;
        return masterService.updateCustomerGroup(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} nhóm đối tượng`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteCustomerGroup(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} nhóm đối tượng`, type: 'success' });
    }
    refresh();
  };

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={() => openAdd()}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        toolbarExtraLeftActions={(
          <CatalogListExportButton
            testIdPrefix={TEST_ID}
            onExport={() => exportCustomerGroupsCsv({ search: search || undefined })}
          />
        )}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{ title: 'Nhóm đối tượng', titleIconClass: 'fas fa-users' }}
        listTitle="Danh sách nhóm đối tượng"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
            <LinListFilterField testId={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={handleSearchDraftChange}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </LinListFilterField>
            <LinListFilterField testId={`${TEST_ID}-field-level`}>
              <Select
                label="Cấp"
                value={levelFilter}
                onChange={e => {
                  setLoadingMode('filter');
                  setLevelFilter(e.target.value);
                  resetPage();
                  selection.clearSelection();
                  setReloadKey(k => k + 1);
                }}
                options={LEVEL_FILTER_OPTIONS}
                fullWidth
              />
            </LinListFilterField>
            <LinListFilterField testId={`${TEST_ID}-field-active`}>
              <Select
                label="Trạng thái"
                value={activeFilter}
                onChange={e => {
                  setLoadingMode('filter');
                  setActiveFilter(e.target.value);
                  resetPage();
                  selection.clearSelection();
                  setReloadKey(k => k + 1);
                }}
                options={ACTIVE_FILTER_OPTIONS}
                fullWidth
              />
            </LinListFilterField>
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {displayRows.length === 0 && !showTableLoading ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{searchDraft.trim() ? 'Không tìm thấy nhóm phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema<GroupGridRow>
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.customerGroupId}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            getTreeRowDepth={isTreeMode ? customerGroupRowDepth : undefined}
            treeIndentPx={CUSTOMER_GROUP_INDENT_PX}
            getRowCellStyle={customerGroupRowCellStyle}
            filterSourceRows={locallyFilteredItems.map(r => ({ ...r, id: r.customerGroupId }))}
            getColumnDisplayValue={getColumnDisplayValue}
            columnFilters={columnFilters}
            onColumnFilterConfirm={handleColumnFilterConfirm}
            onColumnFilterClear={handleColumnFilterClear}
            sortState={sortState}
            onSortChange={handleSortChange}
            {...rowMenu.gridRowMenuProps}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={viewOnlyShared ? 'Xem nhóm đối tượng dùng chung' : editing ? 'Sửa nhóm đối tượng' : 'Thêm nhóm đối tượng'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentCustomerGroupId`}>
              <label className={styles.label}>
                Nhóm cha{formLevel > 1 ? ' *' : ''}
              </label>
              {!editing ? (
                <>
                  <CustomerGroupParentLookupField
                    parentId={form.parentCustomerGroupId}
                    parentCode={form.parentCode}
                    parentName={form.parentName}
                    disabled={viewOnlyShared}
                    error={errors.parentCustomerGroupId}
                    testId={`${TEST_ID}-field-parentCustomerGroupId`}
                    onChange={parent => {
                      markDirty();
                      clearFieldError('parentCustomerGroupId');
                      setForm(f => ({
                        ...f,
                        parentCustomerGroupId: parent.customerGroupId,
                        parentCode: parent.code,
                        parentName: parent.name,
                        customerType: parent.customerType ?? f.customerType,
                      }));
                    }}
                    onClear={() => {
                      markDirty();
                      clearFieldError('parentCustomerGroupId');
                      setForm(f => ({
                        ...f,
                        parentCustomerGroupId: undefined,
                        parentCode: undefined,
                        parentName: undefined,
                      }));
                    }}
                  />
                  <span style={{ fontSize: 12, color: 'var(--ds-color-text-tertiary, #6b7280)' }}>
                    Nhóm L2–L4 chỉ phục vụ quản trị cây danh mục; để trống = cấp 1.
                  </span>
                </>
              ) : (
                <Input
                  value={
                    form.parentCode && form.parentName
                      ? `${form.parentCode} — ${form.parentName}`
                      : form.parentName || form.parentCode || '— Cấp 1 —'
                  }
                  readOnly
                  disabled
                  data-testid={`${TEST_ID}-field-parent-readonly`}
                />
              )}
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã nhóm *</label>
                <Input
                  value={form.code ?? ''}
                  readOnly={!!editing || viewOnlyShared}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  placeholder="Nhập mã nhóm"
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
                <CatalogLegacyCodeSuffix
                  testIdPrefix={TEST_ID}
                  code={editing?.code}
                  legacyCode={editing?.legacyCode}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên nhóm *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            {formLevel === 1 ? (
              <div className={styles.field} data-testid={`${TEST_ID}-field-formatCode`}>
                <label className={styles.label}>Mã format (đối tượng) *</label>
                <Input
                  value={form.formatCode ?? ''}
                  readOnly={viewOnlyShared}
                  disabled={viewOnlyShared}
                  error={errors.formatCode}
                  placeholder="VD: 100 → mã KH 100.001"
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('formatCode');
                    setForm(f => ({ ...f, formatCode: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
            ) : inheritedFormatCode ? (
              <div className={styles.field} data-testid={`${TEST_ID}-field-formatCode-inherited`}>
                <label className={styles.label}>Mã format (nhóm cấp 1)</label>
                <Input
                  value={inheritedFormatCode}
                  readOnly
                  disabled
                  className={styles.codeInput}
                />
              </div>
            ) : null}
            <div className={styles.field} data-testid={`${TEST_ID}-field-customerType`}>
              <label className={styles.label}>Loại{formLevel === 1 ? ' *' : ''}</label>
              <Select
                value={form.customerType ?? 'Customer'}
                disabled={viewOnlyShared || customerTypeLocked}
                error={errors.customerType}
                onChange={e => {
                  markDirty();
                  clearFieldError('customerType');
                  setForm(f => ({ ...f, customerType: e.target.value }));
                }}
                options={customerTypeOpts}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              customerType: form.customerType,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.customerGroupId, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.customerGroupId, code: editing.code } : null}
                />
              </>
            }
            saveDisabled={viewOnlyShared}
          />
        </div>
      </Modal>
    </CatalogCodeReplaceProvider>
  );
};

export default NhomDoiTuongPage;
